class Metabolism{constructor(t){this._model=t}modelStep(){this.is_enabled&&this.modelCycle()}modelCycle(){this.active_comps.forEach((t=>{this.calcEnergyUse(t)}))}calcEnergyUse(t){const o=this._model.components[t.comp],e=t.fvatp,s=e*this.atp_need,c=s*this._model.modeling_stepsize;let l=o.to2*o.vol;const i=.8*l,m=c/5;let n=5*(m-i/4);n<0&&(n=0);let h=m;m>i&&(h=i),l-=h,o.to2=l/o.vol,o.to2<0&&(o.to2=0);const a=h*this.resp_q;o.tco2=(o.tco2*o.vol+a)/o.vol,o.tco2<0&&(o.tco2=0)}}